#include <stdio.h>

int main() {
    int N;
    if (scanf("%d", &N) != 1) return 0;
    int maxVal, x;
    for (int i = 0; i < N; ++i) {
        scanf("%d", &x);
        if (i == 0 || x > maxVal) maxVal = x;
    }
    printf("%d\n", maxVal);
    return 0;
}

